content.problemStatement:
What will be the output of the following C++ program?

```cpp
#include 
using namespace std;

// Function to multiply a number by 2 using pass by reference
void multiplyByTwo(int& num) {
    num = num * 2;  
}

int main() {
    int number = 7;
    multiplyByTwo(number);  // Pass the number by reference
    cout << "Value after multiplication: " << number << endl;  
    return 0;
}
```

